mapper.select:
SELECT member_id, is_admin, email, nickname, user_intro, reg_dt, mod_dt
  FROM member
 WHERE member_id = #{memberId}

SELECT member_id, password, is_admin, email, nickname, user_intro, reg_dt, mod_dt
  FROM member
 WHERE email = #{email}

SELECT COUNT(*)
  FROM member
 WHERE email = #{email}

SELECT COUNT(*)
  FROM member
 WHERE nickname = #{nickname}

   AND member_id != #{memberId}

